/// Verify a V.SAMN.1 algebraic reentry credential.
///
/// `chain`: the receipt chain presented by the reentry claimant (oldest first).
/// `mesh_rcf_majority`: the current modal RCF hash of the mesh.
///
/// Returns `Valid` iff all three conditions hold:
/// 1. Chain length >= CREDENTIAL_CHAIN_DEPTH
/// 2. Every receipt's hash is valid and parent links are correct
/// 3. All rcf_identity values match mesh_rcf_majority
///
/// Register: V.SAMN.1.
pub fn verify_credential(
    chain: &[MeshReceipt],
    mesh_rcf_majority: &[u8; 32],
) -> CredentialResult {
    // Condition 1: sufficient depth
    if chain.len() < CREDENTIAL_CHAIN_DEPTH {
        return CredentialResult::InsufficientDepth {
            got: chain.len(),
            need: CREDENTIAL_CHAIN_DEPTH,
        };
    }

    let mut last_k: Option<u64> = None;
    let mut expected_parent = [0u8; 32]; // genesis parent = all zeros for first receipt

    for (i, receipt) in chain.iter().enumerate() {
        // Condition 2a: hash integrity
        if !receipt.verify_hash() {
            return CredentialResult::ChainBreak { index: i };
        }

        // Condition 2b: parent chain link (skip for first receipt — parent is unknown to verifier)
        if i > 0 && !receipt.verify_parent(&expected_parent) {
            return CredentialResult::ChainBreak { index: i };
        }

        // Condition 3: orbit consistency
        if receipt.rcf_identity != *mesh_rcf_majority {
            return CredentialResult::OrbitMismatch {
                index: i,
                expected: *mesh_rcf_majority,
                got: receipt.rcf_identity,
            };
        }

        // K monotonic
        if let Some(prev_k) = last_k {
            if receipt.k_index <= prev_k {
                return CredentialResult::KNotMonotonic { index: i };
            }
        }

        expected_parent = receipt.receipt_hash;
        last_k = Some(receipt.k_index);
    }

    CredentialResult::Valid
}

